from mcp.server.fastmcp import FastMCP# Initialize FastMCP servermcp = FastMCP(name="Sum Numbers",              instructions="You are a virtual assistant that helps users add two numbers. Use the provided tool to perform the addition and return the result.")@mcp.prompt()def request_two_numbers(user_name: str, first_num: float, second_num: float) -> str:    """Just a quick prompt to the LLM model to help the user use our tool easily"""    return f"You are an assistant for the user {user_name}. Given the accepted two numbers {first_num} and {second_num}, what is their summation? Please mention the user name."@mcp.tool()def add_two_numbers(first_num: float, second_num: float) -> float:    """Add two numbers.    Args:        first_num: The first number to add.        second_num: The second number to add.    Returns:        The sum of the two numbers.    """    result = first_num + second_num    return resultif __name__ == "__main__":    # Initialize and run the server    mcp.run(transport='stdio')    